import { useState } from 'react';
import type { Meta, StoryObj } from '@storybook/react-vite';
import { Drawer } from './Drawer';
import { Button } from '../Button';
import { Text } from '../Text';
import { Space } from '../Space';

const meta = {
  title: 'Components/Drawer',
  component: Drawer,
  tags: ['autodocs'],
  argTypes: {
    title: { control: 'text' },
    direction: { control: 'inline-radio', options: ['rtl', 'ltr', 'ttb', 'btt'] },
    size: { control: 'text' },
    modal: { control: 'boolean' },
    closeOnClickModal: { control: 'boolean' },
    closeOnPressEscape: { control: 'boolean' },
    showClose: { control: 'boolean' },
    withHeader: { control: 'boolean' },
    lockScroll: { control: 'boolean' },
    keepMounted: { control: 'boolean' },
    open: { control: false },
    footer: { control: false },
    onClose: { control: false },
    onOpenChange: { control: false },
  },
  args: {
    // Each story drives `open` from local state via its own `render`; this
    // default just satisfies the required prop for the meta type.
    open: false,
  },
} satisfies Meta<typeof Drawer>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Basic: Story = {
  render: () => {
    const [open, setOpen] = useState(false);
    return (
      <>
        <Button type="primary" onClick={() => setOpen(true)}>
          Open drawer
        </Button>
        <Drawer open={open} onClose={() => setOpen(false)} title="Settings" size={320}>
          <Text>
            Drawers slide in from an edge of the screen and are well suited for forms, filters and
            detail panels.
          </Text>
        </Drawer>
      </>
    );
  },
};

export const Directions: Story = {
  render: () => {
    const [direction, setDirection] = useState<'rtl' | 'ltr' | 'ttb' | 'btt' | null>(null);
    return (
      <>
        <Space wrap>
          <Button onClick={() => setDirection('ltr')}>From left</Button>
          <Button onClick={() => setDirection('rtl')}>From right</Button>
          <Button onClick={() => setDirection('ttb')}>From top</Button>
          <Button onClick={() => setDirection('btt')}>From bottom</Button>
        </Space>
        <Drawer
          open={direction !== null}
          onClose={() => setDirection(null)}
          title="Navigation"
          direction={direction ?? 'rtl'}
          size="40%"
        >
          <Text>This drawer slides in from the {direction} edge.</Text>
        </Drawer>
      </>
    );
  },
};

export const WithFooter: Story = {
  name: 'With a footer',
  render: () => {
    const [open, setOpen] = useState(false);
    return (
      <>
        <Button onClick={() => setOpen(true)}>Edit profile</Button>
        <Drawer
          open={open}
          onClose={() => setOpen(false)}
          title="Edit profile"
          size={360}
          footer={
            <Space>
              <Button onClick={() => setOpen(false)}>Cancel</Button>
              <Button type="primary" onClick={() => setOpen(false)}>
                Save changes
              </Button>
            </Space>
          }
        >
          <Text>Update your display name, avatar and contact details here.</Text>
        </Drawer>
      </>
    );
  },
};

import {
  type CSSProperties,
  forwardRef,
  type HTMLAttributes,
  type ReactNode,
  useId,
} from 'react';
import {
  FloatingFocusManager,
  FloatingOverlay,
  FloatingPortal,
  useDismiss,
  useFloating,
  useInteractions,
  useRole,
} from '@floating-ui/react';
import { cls, useNamespace } from '../../utils';

function CloseIcon() {
  return (
    <svg viewBox="0 0 24 24" width="1em" height="1em" aria-hidden="true" focusable="false">
      <path
        fill="currentColor"
        d="M13.41 12l5.3-5.29a1 1 0 1 0-1.42-1.42L12 10.59l-5.29-5.3a1 1 0 0 0-1.42 1.42l5.3 5.29-5.3 5.29a1 1 0 0 0 0 1.42 1 1 0 0 0 1.42 0L12 13.41l5.29 5.3a1 1 0 0 0 1.42 0 1 1 0 0 0 0-1.42z"
      />
    </svg>
  );
}

export type DrawerDirection = 'rtl' | 'ltr' | 'ttb' | 'btt';

export interface DrawerProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
  /** Controlled visibility. */
  open: boolean;
  /** Called when the drawer requests to close (escape, overlay click, close button). */
  onClose?: () => void;
  /** Called whenever the open state should change. */
  onOpenChange?: (open: boolean) => void;
  /** Title shown in the header. */
  title?: ReactNode;
  /** Edge the panel slides in from. Default `'rtl'` (slides in from the right). */
  direction?: DrawerDirection;
  /**
   * Panel size. Drives the width for `rtl`/`ltr` and the height for
   * `ttb`/`btt`. Default `'30%'`.
   */
  size?: number | string;
  /** Show the backdrop. Default `true`. */
  modal?: boolean;
  /** Close when clicking the overlay. Default `true`. */
  closeOnClickModal?: boolean;
  /** Close when pressing Escape. Default `true`. */
  closeOnPressEscape?: boolean;
  /** Show the close button. Default `true`. */
  showClose?: boolean;
  /** Render the header region. Default `true`. */
  withHeader?: boolean;
  /** Footer content. */
  footer?: ReactNode;
  /** Lock body scroll while open. Default `true`. */
  lockScroll?: boolean;
  /** Keep the drawer mounted while closed. Default `false`. */
  keepMounted?: boolean;
  children?: ReactNode;
}

export const Drawer = forwardRef<HTMLDivElement, DrawerProps>(function Drawer(props, ref) {
  const {
    open,
    onClose,
    onOpenChange,
    title,
    direction = 'rtl',
    size = '30%',
    modal = true,
    closeOnClickModal = true,
    closeOnPressEscape = true,
    showClose = true,
    withHeader = true,
    footer,
    lockScroll = true,
    keepMounted = false,
    className,
    style,
    children,
    ...rest
  } = props;

  const ns = useNamespace('drawer');
  const reactId = useId();
  const titleId = `${ns.b()}-title-${reactId}`;

  const emitClose = () => {
    onOpenChange?.(false);
    onClose?.();
  };

  const handleOpenChange = (next: boolean) => {
    if (next) {
      onOpenChange?.(true);
    } else {
      emitClose();
    }
  };

  const { refs, context } = useFloating({
    open,
    onOpenChange: handleOpenChange,
  });

  const dismiss = useDismiss(context, {
    outsidePress: modal && closeOnClickModal,
    escapeKey: closeOnPressEscape,
  });
  const role = useRole(context, { role: 'dialog' });
  const { getFloatingProps } = useInteractions([dismiss, role]);

  if (!open && !keepMounted) return null;

  // Horizontal drawers are sized by width, vertical drawers by height.
  const isHorizontal = direction === 'rtl' || direction === 'ltr';
  const sizeValue = typeof size === 'number' ? `${size}px` : size;

  const panelClasses = cls(ns.b(), ns.m(direction), className);

  const panelStyle: CSSProperties = {
    [ns.cssVar('size')]: sizeValue,
    ...style,
  } as CSSProperties;

  const {
    'aria-label': ariaLabel,
    'aria-labelledby': ariaLabelledByProp,
    ...restProps
  } = rest as HTMLAttributes<HTMLDivElement>;

  // Expose an accessible name: prefer a consumer-supplied label, otherwise
  // reference the rendered title via its id (only when a header is rendered).
  const hasInternalLabel = withHeader && title != null;
  const ariaLabelledBy =
    ariaLabelledByProp ?? (!ariaLabel && hasInternalLabel ? titleId : undefined);

  const panel = (
    <FloatingFocusManager context={context} modal={modal} initialFocus={refs.floating}>
      <div
        ref={(node) => {
          refs.setFloating(node);
          if (typeof ref === 'function') ref(node);
          else if (ref) ref.current = node;
        }}
        className={panelClasses}
        style={panelStyle}
        data-direction={direction}
        role="dialog"
        aria-modal={modal || undefined}
        aria-label={ariaLabel}
        aria-labelledby={ariaLabelledBy}
        {...getFloatingProps(restProps)}
      >
        {withHeader && (
          <header className={cls(ns.e('header'), ns.is('with-close', showClose))}>
            <span id={titleId} className={ns.e('title')}>
              {title}
            </span>
            {showClose && (
              <button
                type="button"
                className={ns.e('close')}
                aria-label="Close"
                onClick={emitClose}
              >
                <CloseIcon />
              </button>
            )}
          </header>
        )}
        <div className={ns.e('body')}>{children}</div>
        {footer != null && <div className={ns.e('footer')}>{footer}</div>}
      </div>
    </FloatingFocusManager>
  );

  return (
    <FloatingPortal>
      {(open || keepMounted) &&
        (modal ? (
          <FloatingOverlay
            className={cls('ec-overlay', ns.e('mask'), ns.is('hidden', !open))}
            lockScroll={lockScroll && open}
            style={{
              display: open ? undefined : 'none',
              zIndex: 'var(--ec-index-popper)' as unknown as number,
            }}
          >
            <div className={cls(ns.e('wrapper'), ns.m(direction), ns.is('horizontal', isHorizontal))}>
              {panel}
            </div>
          </FloatingOverlay>
        ) : (
          // Non-modal: render no full-screen hit-testing overlay so the page
          // behind stays interactive. Only the panel re-enables pointer events.
          <div
            className={cls(
              'ec-overlay',
              ns.e('wrapper'),
              ns.m(direction),
              ns.is('horizontal', isHorizontal),
              ns.is('non-modal'),
              ns.is('hidden', !open),
            )}
            style={{
              display: open ? undefined : 'none',
              zIndex: 'var(--ec-index-popper)' as unknown as number,
            }}
          >
            {panel}
          </div>
        ))}
    </FloatingPortal>
  );
});

/*
 * The shared `.ec-overlay` rules live in dialog.css. The Drawer reuses that
 * fixed full-screen container and adds its own mask + edge-pinned panel.
 */

.ec-drawer__mask {
  background-color: var(--ec-drawer-overlay-color, rgba(0, 0, 0, 0.5));
  animation: ec-drawer-fade-in var(--ec-transition-duration) var(--ec-transition-function-fast-bezier);
}

/*
 * Wrapper pins the panel to the relevant edge of the viewport. Each direction
 * lays the panel out against one side using flexbox alignment.
 */
.ec-drawer__wrapper {
  display: flex;
  box-sizing: border-box;
  width: 100%;
  height: 100%;
}

.ec-drawer__wrapper.ec-drawer--rtl {
  justify-content: flex-end;
}
.ec-drawer__wrapper.ec-drawer--ltr {
  justify-content: flex-start;
}
.ec-drawer__wrapper.ec-drawer--ttb {
  align-items: flex-start;
}
.ec-drawer__wrapper.ec-drawer--btt {
  align-items: flex-end;
}

/*
 * Non-modal wrapper: no masking layer is rendered, so the full-screen wrapper
 * must let pointer events fall through to the page behind it. Only the drawer
 * panel itself re-enables pointer events.
 */
.ec-drawer__wrapper.is-non-modal {
  pointer-events: none;
}
.ec-drawer__wrapper.is-non-modal .ec-drawer {
  pointer-events: auto;
}

.ec-drawer {
  --ec-drawer-size: 30%;
  --ec-drawer-padding-primary: 16px;
  --ec-drawer-bg-color: var(--ec-bg-color);
  --ec-drawer-title-font-size: var(--ec-font-size-large);
  --ec-drawer-content-font-size: var(--ec-font-size-base);
  --ec-drawer-font-line-height: 1.5;
  --ec-drawer-box-shadow: var(--ec-box-shadow);

  display: flex;
  flex-direction: column;
  box-sizing: border-box;
  padding: var(--ec-drawer-padding-primary);
  background-color: var(--ec-drawer-bg-color);
  box-shadow: var(--ec-drawer-box-shadow);
  color: var(--ec-text-color-regular);
  font-family: var(--ec-font-family);
  font-size: var(--ec-drawer-content-font-size);
  outline: none;
}

/* Horizontal drawers (rtl / ltr) fill the height; `size` controls the width. */
.ec-drawer--rtl,
.ec-drawer--ltr {
  width: var(--ec-drawer-size);
  max-width: 100%;
  height: 100%;
}

/* Vertical drawers (ttb / btt) fill the width; `size` controls the height. */
.ec-drawer--ttb,
.ec-drawer--btt {
  width: 100%;
  height: var(--ec-drawer-size);
  max-height: 100%;
}

/* ---- Slide-in transitions, one per edge ---- */
.ec-drawer--rtl {
  animation: ec-drawer-slide-rtl var(--ec-transition-duration) var(--ec-transition-function-fast-bezier);
}
.ec-drawer--ltr {
  animation: ec-drawer-slide-ltr var(--ec-transition-duration) var(--ec-transition-function-fast-bezier);
}
.ec-drawer--ttb {
  animation: ec-drawer-slide-ttb var(--ec-transition-duration) var(--ec-transition-function-fast-bezier);
}
.ec-drawer--btt {
  animation: ec-drawer-slide-btt var(--ec-transition-duration) var(--ec-transition-function-fast-bezier);
}

.ec-drawer__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  margin-bottom: var(--ec-drawer-padding-primary);
}

.ec-drawer__title {
  flex: 1;
  margin: 0;
  font-size: var(--ec-drawer-title-font-size);
  line-height: var(--ec-drawer-font-line-height);
  color: var(--ec-text-color-primary);
}

.ec-drawer__close {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  width: 24px;
  height: 24px;
  padding: 0;
  margin: 0;
  font-size: 16px;
  background: transparent;
  border: none;
  outline: none;
  cursor: pointer;
  color: var(--ec-text-color-secondary);
  transition: var(--ec-transition-color);
}

.ec-drawer__close:hover {
  color: var(--ec-color-primary);
}

.ec-drawer__close:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: 1px;
}

.ec-drawer__body {
  flex: 1;
  overflow: auto;
  font-size: var(--ec-drawer-content-font-size);
  line-height: var(--ec-drawer-font-line-height);
  color: var(--ec-text-color-regular);
}

.ec-drawer__footer {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 8px;
  margin-top: var(--ec-drawer-padding-primary);
  box-sizing: border-box;
}

@keyframes ec-drawer-fade-in {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes ec-drawer-slide-rtl {
  from {
    transform: translateX(100%);
  }
  to {
    transform: translateX(0);
  }
}

@keyframes ec-drawer-slide-ltr {
  from {
    transform: translateX(-100%);
  }
  to {
    transform: translateX(0);
  }
}

@keyframes ec-drawer-slide-ttb {
  from {
    transform: translateY(-100%);
  }
  to {
    transform: translateY(0);
  }
}

@keyframes ec-drawer-slide-btt {
  from {
    transform: translateY(100%);
  }
  to {
    transform: translateY(0);
  }
}
